import { Injectable } from '@angular/core';
import { environment } from 'src/environments/environment';
import { HttpClient, HttpHeaders, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

const httpOptions = {
  headers: new HttpHeaders({
    'Content-Type':  'application/x-www-form-urlencoded' ,
    'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Allow-Methods': 'GET,POST,OPTIONS,DELETE,PUT',
    'Access-Control-Allow-Origin': '*'   
  })
};

const httpOptionsPago = {
  headers: new HttpHeaders({
    'Content-Type':  'application/x-www-form-urlencoded'    
  })
};

const body = new HttpParams()
  .set('username',environment.paypertics.username)
  .set('password',environment.paypertics.password)
  .set('grant_type',environment.paypertics.grant_type)
  .set('client_id',environment.paypertics.client_id)
  .set('client_secret',environment.paypertics.client_secret);

@Injectable({
  providedIn: 'root'
})
export class FacturasService {

  
  constructor(private http: HttpClient) { }

  getAutorizacionEntidad():Observable<any>{    
      return this.http.post('https://a.paypertic.com/auth/realms/entidades/protocol/openid-connect/token',body.toString(),httpOptions)    
  }

  
  nuevaTransaccion(facturas:any[],cliente:number,monto_transaccion:number):Observable<any>{        
    return this.http.post(`${environment.urlapi}pay-per-tics/transaccion`,JSON.stringify({facturas,cliente,monto_transaccion})).pipe(
      map( (numeroTransaccion:string) =>  numeroTransaccion)
    )
  }

  getNuevoPago(autorizacion:string,pago:any):Observable<any>{       
    return this.http.post('https://api.paypertic.com/pagos',JSON.stringify(pago),{
      headers: new HttpHeaders({
        'Content-Type':  'application/json',
        'Cache-Control': 'no-cache',
        'Authorization':`Bearer ${autorizacion}`    
      })
    })    
}

 

}
