import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';
import { LoginModule } from './login/login.module';
import { AuthGuard } from './login/auth/auth.guard';
import {FacturasModule} from './facturas/facturas.module'
import {LayoutComponent} from './layout/layout.component'
import {RecibosSemestralesModule} from './recibos-semestrales/recibos-semestrales.module'
import {ClienteHomeModule} from './cliente-home/cliente-home.module'

const routes: Routes = [
 { path: '',                             
 component: LayoutComponent,   
                 
    canActivate: [AuthGuard],
    children: [  {
      path: '',                             
      redirectTo: '/home', pathMatch: 'full', 
    },
      {
        path:'home',        
        loadChildren: () => ClienteHomeModule
      },     
      {
        path:'facturas',
        loadChildren: () => FacturasModule
      },
           
      {
        path:'recibos-semestrales',
        loadChildren: () => RecibosSemestralesModule
      }
    ]
  },
  {
    path: 'login',
    loadChildren: () => LoginModule
  },
  { path: '**', redirectTo: '' }
];

@NgModule({
  imports: [RouterModule.forRoot(routes,{
    scrollPositionRestoration: 'enabled',
    anchorScrolling: 'enabled',
  })],
  exports: [RouterModule]
})
export class AppRoutingModule { }
