import { Component, OnInit, OnDestroy } from '@angular/core';
import { Store } from '@ngxs/store';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';
import { Router } from '@angular/router';
import { AuthState } from '../../store/login/state';
import { GetFacturasResumen } from 'src/app/store/factura/actions';
import { GetReciboSemestralResumen } from 'src/app/store/recibo/actions';

@Component({
  selector: 'app-pay-per-tics',
  templateUrl: './pay-per-tics.component.html',
  styleUrls: ['./pay-per-tics.component.css']
})
export class PayPerTicsComponent implements OnInit,OnDestroy {
  
  urlForm:SafeResourceUrl
  constructor(private store:Store,private sanitizer: DomSanitizer,private router: Router) { }

  ngOnInit(): void {
    this.store.select(state => state.reciboSemestral.payPerTicsUrl).subscribe(
      urlReturn => this.urlForm = this.sanitizer.bypassSecurityTrustResourceUrl(urlReturn)
    )
  }

  salir(){
    this.router.navigate(['/recibos-semestrales/pagar'])
}

  ngOnDestroy() {
    const id_cliente = this.store.selectSnapshot(AuthState.cliente);    
    if (!id_cliente==false){
      this.store.dispatch(new GetFacturasResumen(id_cliente))
      this.store.dispatch(new GetReciboSemestralResumen(id_cliente))
    }
    
  }

}
