import { Component, OnInit } from '@angular/core';
import {FacturasService} from '../services/facturas.service'
import { first } from 'rxjs/operators';
import {PagoFacturasClass} from './pago-facturas'
import { Cliente } from 'src/app/store/cliente/model';
import { Store } from '@ngxs/store';
import { SetFormPayPerTics } from 'src/app/store/factura/actions';
import { Router } from '@angular/router';
declare var $:any;

@Component({
  selector: 'app-pago-facturas',
  templateUrl: './pago-facturas.component.html',
  styleUrls: ['./pago-facturas.component.css']
})
export class PagoFacturasComponent implements OnInit {

  public cliente: Cliente;
  
  totalACobrar =0
  mostrarFacturasPagas=false
  facturasSeleccionadasParaPago = []
  estaProcesando:boolean=false
  sinFacturasParaPagar:boolean=false

  constructor(private fs:FacturasService,private store:Store,private router: Router) { }

  ngOnInit(): void {
    this.store.select(state => state.cliente.cliente).pipe(first()).subscribe(
      clienteR => this.cliente = clienteR
    )
  }

  sinFacturasParaAbonar(e){
    this.sinFacturasParaPagar = true
  }

  cambioSeleccionPagoFacturas(facturas){
    let montoPagar = 0
    facturas.forEach(factura=>montoPagar += +factura.total)
    this.totalACobrar = +montoPagar.toFixed(2)

    this.facturasSeleccionadasParaPago = facturas
  }

  pagar(){
    // solicitamos el mail en caso de no poseerlo antes de continuar  
    if(!this.cliente.email ||this.cliente.email == ''){
      $('#mailRequerido').modal('show')
    }else{
      this.estaProcesando = true
      //obtenemos la autorizacion a pay per tics
      this.fs.getAutorizacionEntidad().pipe(first()).subscribe(
        data => { this.generarPagoEtapa1(data.access_token)}
      )
    }
  }

  generarPagoEtapa1(autorizacion:string){
    // Debemos crear la nueva transaccion
    //1. Obtenemos las facturas seleccionadas
    let facturas= this.facturasSeleccionadasParaPago.map( (factura:any)=>{ return {'factura_recibo':factura.factura,'total':factura.total,'recargo':factura.recargo,'ivaRecargo':factura.ivaRecargo} } )
    
    //2. generamos la transaccion
    this.fs.nuevaTransaccion(facturas,this.cliente.idSocio,this.totalACobrar).pipe(first()).subscribe(
      numTransaccion =>{
        //generamos el pago
        this.generarPagoEtapa2(autorizacion,numTransaccion)       
      } 
    )
  }

  generarPagoEtapa2(autorizacion:string,numeroTransaccion:string){
    let pago:PagoFacturasClass = new PagoFacturasClass()
    pago.addIdPago(numeroTransaccion)
    this.facturasSeleccionadasParaPago.forEach(factura=> pago.addDetalle(factura.factura,`Pago factura periodo ${factura.id_periodo}`,factura.total))
    pago.addPagador(this.cliente.clienteNumero,this.cliente.nombre,this.cliente.email)
    
    // enviamos la consulta a pay per tics
     this.fs.getNuevoPago(autorizacion,pago).pipe(first()).subscribe(
      data=> {
        this.estaProcesando = false
        // seteamos la url con el formulario de retorno y la mostramos
        this.store.dispatch(new SetFormPayPerTics(data.form_url));
        this.router.navigate(['/facturas/formulario/pagos'])
      } 
    ) 
    
  }

  cancelar(){
    $('#mailRequerido').modal('hide')
  }
  actualizarDatos(){
    $('#mailRequerido').modal('hide')
    this.router.navigate(['/home/actualizar'])
  }

}
