import * as dayjs from 'dayjs'
import { environment } from 'src/environments/environment';
class Pagador{
    external_reference:string;
    name:string;
    email:string;
}
class Detalle{
    external_reference:string;       //numero de factura a pagar
    concept_id: string;         //utilizaremos el "1" -> pago de agua
    concept_description:string;   // periodo a abonar formato AAAAMM
    amount:number;                // total de factura a pagar   
 }
 interface PagoFacturas{
    currency_id:string;               // seteado a "ARS"
    external_transaction_id: string;  // lo obtendremos de la api  
    due_date:string; // fecha de hoy
    last_due_date:string; // fecha de hoy
    details: Detalle[];        
    payer:Pagador;
}

export class PagoFacturasClass implements PagoFacturas {

    currency_id:string;               // seteado a "ARS"
    external_transaction_id: string;  // lo obtendremos de la api  
    due_date:string; // fecha de hoy
    last_due_date:string; // fecha de hoy
    details: Detalle[] = [];        
    payer:Pagador;
    notification_url:string;
     
    constructor(){
         
        this.currency_id="ARS"
        let date = dayjs().add(1, 'day').format("YYYY-MM-DD[T]HH:mm:ssZZ")
        this.due_date= date
        this.last_due_date = date
        this.notification_url = `${environment.urlNotificacionPaypertics}/cooperativavirtualrest/pay-per-tics/notifications`
    }

    addIdPago(id:string){
        this.external_transaction_id = id
    }

    addDetalle(numFactura:string,detalle_desc:string,total:number){
        let detalle:Detalle = new Detalle()
        detalle.external_reference=numFactura
        detalle.concept_id ="1"
        detalle.concept_description=detalle_desc
        detalle.amount = total
       this.details.push(detalle) 
    }

    addPagador(socio:string,nombre:string,email:string){
        let pagador:Pagador = new Pagador()
        pagador.external_reference=socio          // codsocio + subcodsocio
        pagador.name = nombre
        pagador.email = email
        this.payer = pagador
    }
}
